BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "transaksi_lokal" (
	"id_transaksi"	TEXT,
	"no_faktur"	TEXT,
	"id_kasir"	TEXT,
	"total_bayar"	INTEGER,
	"waktu"	TEXT,
	"is_synced"	INTEGER DEFAULT 0,
	"uang_tunai"	REAL DEFAULT 0,
	"kembalian"	REAL DEFAULT 0,
	"metode_pembayaran"	TEXT DEFAULT 'Tunai',
	"keterangan_sinkron"	TEXT,
	PRIMARY KEY("id_transaksi")
);
CREATE TABLE IF NOT EXISTS "detail_transaksi_lokal" (
	"id_detail"	INTEGER,
	"id_transaksi"	TEXT,
	"kode_barang"	TEXT,
	"berat"	REAL,
	"subtotal"	INTEGER,
	FOREIGN KEY("id_transaksi") REFERENCES "transaksi_lokal"("id_transaksi"),
	PRIMARY KEY("id_detail" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "riwayat_z_report" (
	"id_z"	INTEGER,
	"waktu_tutup"	TEXT,
	"id_kasir"	TEXT,
	"total_nota"	INTEGER,
	"omzet_bersih"	REAL,
	"uang_wajib_setor"	REAL,
	PRIMARY KEY("id_z" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "akun_pengguna" (
	"username"	TEXT,
	"password_hash"	TEXT NOT NULL,
	"peran"	TEXT NOT NULL,
	"nama_lengkap"	TEXT NOT NULL,
	"terakhir_login"	TEXT,
	"is_active"	BOOLEAN NOT NULL,
	"created_at"	TEXT,
	"updated_at"	TEXT,
	"nomor_karyawan"	TEXT,
	"atasan_username"	TEXT,
	FOREIGN KEY("atasan_username") REFERENCES "akun_pengguna"("username"),
	PRIMARY KEY("username")
);
CREATE TABLE IF NOT EXISTS "barang_lokal" (
	"id_barang"	TEXT,
	"nama_barang"	TEXT NOT NULL,
	"satuan"	TEXT NOT NULL,
	"stok_aktual"	REAL DEFAULT 0.00,
	"harga_beli_terakhir"	INTEGER DEFAULT 0,
	"harga_jual"	INTEGER DEFAULT 0,
	"metode_pembayaran"	TEXT DEFAULT 'Tunai',
	"created_at"	TEXT,
	"updated_at"	TEXT,
	"barcode"	TEXT,
	PRIMARY KEY("id_barang")
);
COMMIT;
